import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';
import { QRCodeSVG } from 'qrcode.react';
import Scanner from './Scanner';

function App() {
  // 1. Create a "box" (state) to hold our products
  const [products, setProducts] = useState([]);

  const [showScanner, setShowScanner] = useState(false);
  const handleScan = async (sku) => {
  // Only process if scanner is actually open
  if (!showScanner) return; 

  console.log("Scanned SKU:", sku);
  setShowScanner(false); // Close scanner immediately

  const product = products.find(p => p.sku === sku);
  if (product) {
    updateStock(product.id, product.quantity + 1);
    alert(`Success! Added 1 unit to ${product.name}`);
  } else {
    alert(`SKU ${sku} not found in inventory.`);
  }
};

  // 2. The function that calls the Django API
  const fetchProducts = async () => {
    try {
      const response = await axios.get('http://127.0.0.1:8000/api/products/');
      setProducts(response.data); // Put the data in our box
    } catch (error) {
      console.error("Error fetching data:", error);
    }
  };

  // 3. Tell React to run the function when the page loads
  useEffect(() => {
    fetchProducts();
  }, []);

  // ... inside the App() function, above the return statement:

const updateStock = async (id, newQuantity) => {
  if (newQuantity < 0) return; // Prevent negative stock
  try {
    await axios.patch(`http://127.0.0.1:8000/api/products/${id}/`, {
      quantity: newQuantity
    });
    fetchProducts(); // Refresh the list
  } catch (error) {
    console.error("Error updating stock:", error);
  }
};



return (
  <div className="App">
    <h1>Smart Warehouse Dashboard</h1>


    <div style={{ textAlign: 'center', marginBottom: '30px' }}>
      <button 
        className="btn-add" 
        style={{ padding: '15px 30px', fontSize: '1.2rem' }}
        onClick={() => setShowScanner(!showScanner)}
      >
        {showScanner ? "Close Scanner" : "Scan Item to Add Stock"}
      </button>

      {showScanner && (
        <div style={{ marginTop: '20px' }}>
          <Scanner onScanSuccess={handleScan} />
        </div>
      )}
    </div>

    <div className="inventory-list">
      <h2>Current Inventory</h2>
      <table>
        <thead>
          <tr>
            <th>Name</th>
            <th>SKU</th>
            <th>QR Code</th>
            <th>Quantity</th>
            <th>Price</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {products.map(product => (
            <tr key={product.id}>
              <td>{product.name}</td>
              <td>{product.sku}</td>
              <td>
                <QRCodeSVG 
  value={product.sku} 
  size={80} 
  level="H" // High error correction
  includeMargin={true}
/>
              </td>
              <td>
                <span className={`stock-badge ${product.quantity < 5 ? 'low-stock' : ''}`}>
                  {product.quantity}
                </span>
              </td>
              <td>${product.price}</td>
              <td>
                <button className="btn-add" onClick={() => updateStock(product.id, product.quantity + 1)}>+</button>
                <button className="btn-remove" onClick={() => updateStock(product.id, product.quantity - 1)}>-</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  </div>
);
}
export default App;
